+  name: "process_exit_function",
+  pass: typeof process.exit === "function",
+  detail: `process.exit is ${typeof process.exit}`
+});
+
+// TypeError shape
+try {
+  null.foo;
+} catch (err) {
+  result.checks.push({
+    name: "typeerror_name",
+    pass: err.name === "TypeError",
